import lxml.etree as ET

def process_soap_request(request):
    # Validate the request against the DTD
    dtd = ET.DTD("http://www.w3.org/2001/XMLSchema")
    if not dtd.validate(request):
        raise ValueError("Invalid SOAP request")
    
    # Parse the SOAP envelope
    root = ET.fromstring(request)
    
    # Extract the message body
    body = root.find(".//soap:Body", namespaces={"soap": "http://www.w3.org/2003/05/soap-envelope/"})
    
    # Return the extracted message body
    return body